        columns="units_sold",
        value=500,
        segments=("genre", pb.seg_group([
            ["Fantasy", "Science Fiction"],
            ["Fantasy", "Mystery"],
            ["Mystery", "Science Fiction"]
        ]))
    )
    .interrogate()
)

